mapper.select:
select t.*,
       l.asset_name,
       l.asset_code,
       l.asset_no,
       (select d.`value` from t_sys_dict d where d.type = 'asset_type' and d.`code` = l.asset_type limit 1) asset_type,
       (select d.`value` from t_sys_dict d where d.type = concat('asset_type_', l.asset_type) and d.`code` = l.asset_sub_type limit 1) asset_sub_type,
       i.`name` as invoiceOwnerName
from t_asset_transaction t
join t_asset_ledger l
  on t.asset_ledger_id = l.id
join t_sys_person_info i
  on i.account_id = t.invoice_owner


        and t.invoice_no like concat('%', #{invoiceNo}, '%')


        and t.invoice_action like concat('%', #{invoiceAction}, '%')


        and t.record_time >= #{recordTimeStart}


        and t.record_time <= #{recordTimeEnd}


        and t.amount >= #{amount}


        and t.asset_ledger_id = #{assetLedgerId}


        and t.transaction_type = #{transactionType}


        and t.invoice_type in

            #{item}



        and t.spending_type in

            #{item}



        and t.income_type in

            #{item}



        and t.settlement_status = #{settlementStatus}


        and t.invoice_owner = #{invoiceOwner}


        and t.data_source in

            #{item}



order by t.record_time desc

select (select d.`value`
        from t_sys_dict d
        where d.type = 'transaction_type' and d.`code` = t.transaction_type limit 1) transaction_type,
       sum(t.amount) transaction_amount
from t_asset_transaction t


        and t.invoice_no like concat('%', #{invoiceNo}, '%')


        and t.invoice_action like concat('%', #{invoiceAction}, '%')


        and t.record_time >= #{recordTimeStart}


        and t.record_time <= #{recordTimeEnd}


        and t.amount >= #{amount}


        and t.asset_ledger_id = #{assetLedgerId}


        and t.transaction_type = #{transactionType}


        and t.invoice_type in

            #{item}



        and t.spending_type in

            #{item}



        and t.income_type in

            #{item}



        and t.settlement_status = #{settlementStatus}


        and t.invoice_owner = #{invoiceOwner}


        and t.data_source in

            #{item}



group by t.transaction_type
